  const CRUISER_MAX_HP = 375;
  const SUBMARINE_MAX_HP = 220;
  const CRUISER_ATTACK = 36.25;
  const SUBMARINE_ATTACK = 96.2;

  while (cruiserHP > 0 && submarineHP > 0) {
    hour++;

