    let cruiserDamage = (cruiserHP / CRUISER_MAX_HP) * CRUISER_ATTACK;
    let submarineDamage = (submarineHP / SUBMARINE_MAX_HP) * SUBMARINE_ATTACK;

    // Apply the damage to each stack
