    cruiserHP -= submarineDamage;

    // If one stack has been destroyed, break out of the loop
    if (submarineHP <= 0 || cruiserHP <= 0) {
      break;
    }

    // Retaliation phase, where damage is again based on remaining HP
    cruiserDamage = (cruiserHP / CRUISER_MAX_HP) * CRUISER_ATTACK;
    submarineDamage = (submarineHP / SUBMARINE_MAX_HP) * SUBMARINE_ATTACK;

    submarineHP -= cruiserDamage;
    cruiserHP -= submarineDamage;

    // Print out the status every hour (not necessary, but helpful for observing the simulation)
    console.log(`Hour ${hour}, Cruiser HP: ${cruiserHP.toFixed(2)}, Submarine HP: ${submarineHP.toFixed(2)}`);
  }

