    // Calculate the damage per living submarine unit and deal it to each cruiser unit
    let submarineAttack = (96.2 / 5) * (submarines.length / 5); // Adjust the Submarine attack
    for (let i = 0; i < cruisers.length; i++) {
      cruisers[i] -= submarineAttack;
    }

    // Remove destroyed cruiser units
    cruisers = cruisers.filter(hp => hp > 0);

    if (cruisers.length === 0 || submarines.length === 0) {
