    for (let i = 0; i < submarines.length; i++) {
      submarines[i] -= cruiserAttack;
    }

    // Remove destroyed submarine units
    submarines = submarines.filter(hp => hp > 0);

    // Retaliation phase for submarines
    submarineAttack = (96.2 / 5) * (submarines.length / 5);
    for (let i = 0; i < cruisers.length; i++) {
      cruisers[i] -= submarineAttack;
    }

    // Remove destroyed cruiser units
    cruisers = cruisers.filter(hp => hp > 0);

    // Print out the status every hour (not necessary, but helpful for observing the simulation)
    console.log(`Hour ${hour}, Cruiser Units: ${cruisers.length}, Cruiser HP: ${cruisers}, Submarine Units: ${submarines.length}, Submarine HP: ${submarines}`);
