To optimize the script, we can integrate the officers into their respective stacks and compact the logic by utilizing modern JavaScript features like array destructuring and higher-order array functions. Let's update the code accordingly:

```javascript
function calculateAttack(stack) {
  return stack.reduce((total, unit) => total + unit.attack * (1 + unit.attackBuff), 0);
}

function calculateDefense(stack) {
  return stack.reduce((total, unit) => total + unit.defense * (1 + unit.defenseBuff), 0);
}

function applyDamage(stack, damage) {
  const damagePerUnit = damage / stack.length;
  stack.forEach(unit => unit.hp -= damagePerUnit);
  return stack.filter(unit => unit.hp > 0);
}

function battleSimulation() {
  let cruiserStack = Array(4).fill({ hp: 40, attack: 5, defense: 5, attackBuff: 0.25, defenseBuff: 0.30 });
  cruiserStack.push({ hp: 75, attack: 9, defense: 9, attackBuff: 0, defenseBuff: 0 }); // Naval Officer

  let subStack = Array(4).fill({ hp: 75, attack: 15, defense: 15, attackBuff: 0.25, defenseBuff: 0.30 });
  subStack.push({ hp: 60, attack: 14, defense: 14, attackBuff: 0, defenseBuff: 0 }); // Submarine Officer

  let hour = 0;

  while (cruiserStack.length > 0 && subStack.length > 0) {
    hour++;
    const cruiserAttack = calculateAttack(cruiserStack);
    const subAttack = calculateAttack(subStack);

    subStack = applyDamage(subStack, cruiserAttack);
    cruiserStack = applyDamage(cruiserStack, subAttack);

    if (cruiserStack.length === 0 || subStack.length === 0) break;

    const cruiserDefense = calculateDefense(cruiserStack);
    const subDefense = calculateDefense(subStack);

    subStack = applyDamage(subStack, cruiserDefense);
    cruiserStack = applyDamage(cruiserStack, subDefense);

    console.log(`Hour ${hour}, Cruisers: ${JSON.stringify(cruiserStack)}, Submarines: ${JSON.stringify(subStack)}`);
  }

  return cruiserStack.length === 0 ? `Submarines win after ${hour} hours!` 
         : subStack.length === 0 ? `Cruisers win after ${hour} hours!` 
         : "It's a draw, which should never happen.";
}

console.log(battleSimulation());
```

