  return { 
    attackBonus: unit.attack * (1 + unit.attackBuff),
    defenseBonus: unit.defense * (1 + unit.defenseBuff) 
  };
}

function attackStack(attackingStack, defendingStack) {
  let totalDamage = attackingStack.reduce((sum, unit) => {
    const { attackBonus } = calculateBonus(unit);
    return sum + attackBonus;
  }, 0);

  for (let unit of defendingStack) {
    if (totalDamage <= 0) break;
    let damageToApply = Math.min(unit.hp, totalDamage);
    unit.hp -= damageToApply;
    totalDamage -= damageToApply;
  }

  return defendingStack.filter(unit => unit.hp > 0);
}

